import{_ as s,c as i,o as t,ag as o}from"./chunks/framework.Dj4VfQLU.js";const h=JSON.parse('{"title":"Common errors and resolutions","description":"","frontmatter":{},"headers":[],"relativePath":"common-errors-and-resolutions.md","filePath":"common-errors-and-resolutions.md"}'),n={name:"common-errors-and-resolutions.md"};function a(r,e,l,d,c,p){return t(),i("div",null,e[0]||(e[0]=[o(`<h1 id="common-errors-and-resolutions" tabindex="-1">Common errors and resolutions <a class="header-anchor" href="#common-errors-and-resolutions" aria-label="Permalink to &quot;Common errors and resolutions&quot;">​</a></h1><p>This section outlines frequent issues encountered during installation, configuration, and operation — along with their causes and how to resolve them.</p><hr><h4 id="🔑-license-activation-issues" tabindex="-1">🔑 License &amp; Activation Issues <a class="header-anchor" href="#🔑-license-activation-issues" aria-label="Permalink to &quot;🔑 License &amp; Activation Issues&quot;">​</a></h4><p><strong>❌ License Validation Failed</strong></p><p><strong>Cause</strong>:</p><ul><li>Static IP not used or IP address changed too frequently</li><li>License bound to a different server instance</li></ul><p><strong>Resolution</strong>:</p><ul><li>Ensure the server uses a <strong>static IP</strong></li><li>If license fails or your IP has been <strong>greylisted</strong>, contact support: <ul><li>via your customer panel, or</li><li>email: <a href="mailto:contact@lumeagency.io" target="_blank" rel="noreferrer"><strong>contact@lumeagency.io</strong></a> for reactivation assistance</li></ul></li></ul><hr><h4 id="🐳-install-sh-docker-issues" tabindex="-1">🐳 install.sh / Docker Issues <a class="header-anchor" href="#🐳-install-sh-docker-issues" aria-label="Permalink to &quot;🐳 install.sh / Docker Issues&quot;">​</a></h4><p><strong>❌ install.sh Fails on Setup</strong></p><p><strong>Common Causes</strong>:</p><ul><li>Server already has <strong>PHP</strong>, <strong>MySQL</strong>, <strong>Docker</strong>, <strong>NGINX</strong>, <strong>WHM</strong>, etc., pre-installed</li><li>Conflicting services occupying critical ports (80, 3306, 6379)</li></ul><p><strong>Resolution</strong>:</p><ul><li>Use a <strong>clean Ubuntu 22.04 server</strong></li><li>Avoid shared hosting or cPanel servers</li><li>Disable or uninstall any pre-existing services before running <code>install.sh</code></li></ul><p><strong>🔁 Services Not Running After Reboot</strong></p><p><strong>Resolution</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div><p>This will restart all containers as per the <code>docker-compose.yaml</code>.</p><hr><h4 id="📱-client-app-compilation-issues" tabindex="-1">📱 Client App Compilation Issues <a class="header-anchor" href="#📱-client-app-compilation-issues" aria-label="Permalink to &quot;📱 Client App Compilation Issues&quot;">​</a></h4><p><strong>❌ Firebase Not Working (Push Not Received)</strong></p><p><strong>Cause</strong>:</p><ul><li>Firebase not configured properly</li><li><code>google-services.json</code> (Android) or <code>GoogleService-Info.plist</code> (iOS) missing</li><li>APNs key not uploaded to Firebase for iOS messaging</li></ul><p><strong>Resolution</strong>:</p><ul><li>Use <code>flutterfire configure</code> or follow Firebase setup wizard</li><li>Ensure platform files are placed in respective directories</li><li>For iOS, upload your <strong>APNs authentication key</strong> to Firebase under:<br><code>Firebase Console → Project → Messaging → iOS Push Configuration</code></li></ul><p><strong>⚠️ App Crashes or No Splash/Icon</strong></p><p><strong>Cause</strong>:</p><ul><li>Splash screen or launcher icon not generated</li></ul><p><strong>Resolution</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> flutter_native_splash:create</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> flutter_launcher_icons</span></span></code></pre></div><ul><li>Make sure the <code>flutter_native_splash.yaml</code> is configured with proper image paths and colors</li></ul><hr><h4 id="🗺️-map-configuration-errors" tabindex="-1">🗺️ Map Configuration Errors <a class="header-anchor" href="#🗺️-map-configuration-errors" aria-label="Permalink to &quot;🗺️ Map Configuration Errors&quot;">​</a></h4><p><strong>❌ Map Not Displaying or Blank</strong></p><p><strong>Cause</strong>:</p><ul><li>Missing or incorrect API keys in <code>.env</code></li><li>Using a map provider unsupported on a platform (e.g., Google Maps on desktop)</li></ul><p><strong>Resolution</strong>:</p><ul><li>Double-check <code>.env</code> for <code>MAP_PROVIDER</code> and API key fields</li><li>Adjust per-platform provider in:</li></ul><div class="language-dart vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dart</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">static</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> PlatformMapProviderSettings</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> get</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mapProviderPlatformSettings </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ...</span></span></code></pre></div><ul><li>Refer to <a href="https://pub.dev/packages/generic_map" target="_blank" rel="noreferrer">generic_map pub.dev</a> for compatibility guidelines</li></ul><hr><h4 id="🛑-admin-panel-issues" tabindex="-1">🛑 Admin Panel Issues <a class="header-anchor" href="#🛑-admin-panel-issues" aria-label="Permalink to &quot;🛑 Admin Panel Issues&quot;">​</a></h4><p><strong>❌ Admin Panel Blank or Crashes on Load</strong></p><p><strong>Common Causes</strong>:</p><ul><li><code>.env</code> file missing or incomplete</li><li>Database not reachable</li><li>Redis not started</li></ul><p><strong>Resolution</strong>:</p><ul><li>Verify <code>.env</code> file is copied and all <code># REQUIRED</code> fields are filled</li><li>Ensure <code>admin-api</code> is running</li><li>Use <code>docker compose ps</code> to verify container statuses</li></ul><hr><h4 id="🧠-database-redis-errors" tabindex="-1">🧠 Database &amp; Redis Errors <a class="header-anchor" href="#🧠-database-redis-errors" aria-label="Permalink to &quot;🧠 Database &amp; Redis Errors&quot;">​</a></h4><p><strong>❌ Cannot Connect to MySQL (port 3306)</strong></p><p><strong>Cause</strong>:</p><ul><li>MySQL not running or port conflict</li></ul><p><strong>Resolution</strong>:</p><ul><li>For Docker: check container with <code>docker logs</code></li><li>For local: ensure MySQL is installed and running</li><li>Validate connection using: <code>telnet localhost 3306</code></li></ul><p><strong>❌ Redis Connection Fails (port 6379)</strong></p><p><strong>Cause</strong>:</p><ul><li>Redis not running or blocked by firewall</li></ul><p><strong>Resolution</strong>:</p><ul><li>Verify Redis status via <code>docker ps</code> or <code>systemctl status redis</code></li><li>Confirm Redis is exposed on <code>6379</code> and no other service is blocking it</li></ul><hr><h4 id="💡-quick-debug-checklist" tabindex="-1">💡 Quick Debug Checklist <a class="header-anchor" href="#💡-quick-debug-checklist" aria-label="Permalink to &quot;💡 Quick Debug Checklist&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Symptom</th><th>Likely Cause</th><th>Resolution</th></tr></thead><tbody><tr><td>License validation fails</td><td>IP changed or unlicensed machine</td><td>Contact support, ensure static IP</td></tr><tr><td>install.sh fails</td><td>Pre-installed services on server</td><td>Use fresh Ubuntu instance</td></tr><tr><td>No push notifications</td><td>Firebase misconfigured</td><td>Check <code>google-services.json</code> / APNs key</td></tr><tr><td>Map doesn’t show</td><td>API key/platform mismatch</td><td>Check <code>.env</code>, map provider settings</td></tr><tr><td>Admin panel won’t load</td><td>DB or Redis not up</td><td>Check docker services, logs</td></tr><tr><td>Wallet or earnings not updating</td><td>Backend not syncing or down</td><td>Restart services, validate websocket</td></tr></tbody></table>`,64)]))}const g=s(n,[["render",a]]);export{h as __pageData,g as default};
